-- ============================================================
-- IDEA 1: Takeout Review Cashback Tool
-- Authors: 2, 5, 8
-- ============================================================

INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(1, 2, E'# ReviewBoost: Takeout Review Cashback Automation Platform\n\n## 1. Executive Summary\n\nReviewBoost is a SaaS tool that helps independent restaurant owners automate cashback-for-review campaigns across major delivery platforms (DoorDash, Uber Eats, Grubhub). By integrating with restaurant POS systems and payment apps (Venmo, PayPal, Zelle), it eliminates the manual overhead of tracking which customers left reviews, automating payouts within minutes of review verification. The platform targets US restaurants processing 50–200 daily delivery orders, a segment chronically underserved by enterprise review management tools.\n\n## 2. Market Analysis\n\n| Metric | Value | Source / Notes |\n|---|---|---|\n| US restaurant count (independent) | ~500,000 | NRA 2024 estimate |\n| Avg. delivery orders/day (target segment) | 80–180 | Toast POS benchmark |\n| % of owners running manual review campaigns | ~34% | Podium SMB survey 2024 |\n| Avg. cashback per review (industry) | $1.50–$3.00 | Owner interviews |\n| Monthly churn without review campaigns | 12–18% | Yelp internal 2023 |\n| TAM (US review mgmt for restaurants) | $1.4B | IBISWorld 2024 |\n| SAM (50–200 order/day independents) | ~$180M | Internal sizing |\n| SOM (Year 1, 3 metro areas) | ~$2.1M | Bottom-up estimate |\n\n## 3. Competitive Landscape\n\n| Competitor | Focus | Users | Strengths | Weaknesses |\n|---|---|---|---|---|\n| Podium | Review collection via SMS | 100,000+ SMBs | Multi-platform, strong brand | No cashback automation, $400+/mo |\n| Birdeye | Reputation management suite | 90,000+ | Deep analytics, enterprise-ready | Too complex for small operators |\n| Grade.us | Review generation SaaS | 20,000+ | Affordable, white-label | No payment integration |\n| Stamp Me | Loyalty + review combo | 15,000+ | Simple UX, loyalty features | AU-focused, limited US delivery platform APIs |\n| Manual (Venmo + spreadsheet) | DIY | Most SMBs | Free | No automation, error-prone, time sink |\n\n## 4. Target User Personas\n\n**Persona 1 — Mike, 38, Taco Shop Owner, Denver CO**\nMike runs a family taco restaurant doing ~110 DoorDash orders/day. He manually DMs customers on DoorDash to offer $2 back if they leave a 5-star review, then manually sends Venmo. He spends 45 min/day on this and misses ~30% of eligible reviews because he forgets. He wants the whole thing to "just run itself."\n\n**Persona 2 — Sandra, 44, Owner of Two Pizza Locations, Nashville TN**\nSandra manages two locations with different staff. She tried Podium but found it too expensive and complex for delivery-specific campaigns. Her biggest pain: she can''t easily see which location''s review campaign is performing better, or which customers churned after a bad experience.\n\n**Persona 3 — James, 31, Ghost Kitchen Operator, Los Angeles CA**\nJames runs three virtual brands from one kitchen. He has no front-of-house staff to ask for reviews. Automated post-order cashback is his only realistic lever to drive review volume. He''s comfortable with software but wants API-level control over payout thresholds.\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|---|---|---|\n| P0 | Delivery platform webhook listener | Capture completed orders from DoorDash, Uber Eats, Grubhub in real time |\n| P0 | Review verification engine | Poll platform APIs every 15 min to detect new reviews tied to verified order IDs |\n| P0 | Automated payout via Venmo/PayPal/Zelle | Trigger cashback within 60 min of review verification |\n| P0 | Campaign rules dashboard | Set cashback amount, minimum star rating, daily payout cap per location |\n| P1 | Multi-location management | Separate campaigns per location, unified billing |\n| P1 | Review conversion analytics | Funnel: orders → eligible → review posted → cashback sent → repeat order |\n| P1 | Customer opt-in text flow | Post-order SMS prompting review with cashback offer (Twilio-powered) |\n| P2 | A/B test cashback amounts | Test $1 vs $2 vs $3 payout to find optimal ROI |\n| P2 | Competitor review gap alerts | Alert owner when average competitor rating exceeds theirs by 0.3+ stars |\n| P2 | Accounting export (QuickBooks) | Monthly cashback spend exported as marketing expense line items |\n\n## 6. Technical Architecture\n\n**Tech Stack:**\n- Backend: Node.js 20 + Fastify (low latency webhook processing)\n- Database: PostgreSQL 15 (orders, reviews, payouts) + Redis (dedup queue)\n- Payment APIs: Venmo Business API, PayPal Payouts API, Zelle via bank ACH fallback\n- Delivery APIs: DoorDash Drive API, Uber Eats Orders API, Grubhub Webhook\n- SMS: Twilio Messaging API\n- Frontend: React 18 + Vite + shadcn/ui\n- Hosting: AWS (ECS Fargate + RDS Aurora Serverless)\n- Auth: Auth0 (restaurant owner SSO)\n\n**Architecture Description:**\nWebhook events from delivery platforms land in an SQS queue, processed by a Fastify worker that upserts order records and enqueues a review-check job. A cron worker (every 15 min) polls review endpoints and, upon detecting a matching review, calls the payment API and logs the payout. All state transitions are idempotent using order+review composite keys to prevent double payouts. The React dashboard reads from a read replica for analytics queries, keeping the write path clean.\n\n## 7. Business Model\n\n| Revenue Source | Model | Expected % of Revenue |\n|---|---|---|\n| Monthly SaaS subscription | $79/mo (1 location), $129/mo (2–5 locations) | 70% |\n| Payment processing markup | 0.3% on cashback payouts routed through platform | 18% |\n| SMS add-on | $19/mo for outbound review-request SMS (500 msg/mo) | 8% |\n| Setup & onboarding fee | One-time $99 per account | 4% |\n\n## 8. MVP Roadmap\n\n| Month | Milestone |\n|---|---|\n| M1 | DoorDash webhook integration + PostgreSQL schema + basic campaign rules UI |\n| M2 | Review polling engine + PayPal Payouts integration + manual payout approval flow |\n| M3 | Venmo + Zelle support + Uber Eats integration + analytics dashboard v1 |\n| M4 | Twilio SMS opt-in flow + multi-location support + billing (Stripe) + public beta |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M6 Target |\n|---|---|---|\n| Paying restaurant accounts | 40 | 150 |\n| Monthly recurring revenue | $3,200 | $12,500 |\n| Avg. review conversion rate (order → review) | 8% | 12% |\n| Payout error rate | <1% | <0.3% |\n| Owner-reported time saved/week | 4 hrs | 5 hrs |\n| Net Promoter Score | 35 | 50 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|---|---|---|---|\n| Delivery platforms restrict review API access | High | Critical | Use scraping fallback + maintain human-review verification option |\n| Platform TOS change prohibiting cashback-for-review | Medium | High | Legal review; reframe as "loyalty reward" not "review incentive" |\n| Venmo Business API deprecation | Low | Medium | Multi-payment provider abstraction layer from day one |\n| Restaurant churn due to ROI doubt | Medium | Medium | Build ROI calculator showing review lift → order volume increase |\n| Fraudulent self-reviews | Medium | High | Require order ID match + device fingerprint check before payout |\n', '[{"step":"market_focus","decision":"US-only, DoorDash-first","reason":"DoorDash has 67% US delivery market share; fastest path to integration coverage"},{"step":"tech_stack","decision":"Node.js over Go","reason":"Richer npm ecosystem for payment SDKs; team has Node expertise"},{"step":"payment_approach","decision":"Start with PayPal Payouts, add Venmo M2","reason":"PayPal API most mature; Venmo Business API requires business verification which takes 2-3 weeks"},{"step":"pricing","decision":"$79/mo entry point","reason":"Below Podium''s $400/mo; above perceived free-tier risk; covers COGS at 40+ accounts"},{"step":"go_to_market","decision":"Partner with Toast POS resellers","reason":"Toast has 120,000+ US restaurant clients; channel partnership reduces CAC from $400 to $90 estimated"}]', 'submitted', 47, NOW() - INTERVAL '29 days', NOW() - INTERVAL '30 days', NOW() - INTERVAL '29 days'),

(1, 5, E'# StarCash: Hyperlocal Review Rewards for Independent Restaurants\n\n## 1. Executive Summary\n\nStarCash is a mobile-first review cashback platform purpose-built for independent restaurant owners who depend on delivery apps but lack the marketing budgets of chains. Unlike SaaS-heavy competitors, StarCash takes a marketplace approach: restaurants list cashback offers that diners discover post-order via a branded receipt insert QR code, creating a two-sided network effect. The platform handles all verification and payout logistics, charging a flat 8% fee on cashback distributed — zero monthly subscription — making it uniquely compelling for cash-strapped owners.\n\n## 2. Market Analysis\n\n| Metric | Value | Source / Notes |\n|---|---|---|\n| Independent US restaurants (delivery-enabled) | ~220,000 | Datassential 2024 |\n| Average star rating impact on order volume | +5–9% per 0.1-star gain | Harvard Business School study |\n| % of diners who leave reviews unprompted | ~7% | BrightLocal Consumer Survey 2024 |\n| % who leave reviews when incentivized | ~31% | Same survey, incentive = $2+ |\n| Average delivery order value (US) | $34.20 | Second Measure 2024 |\n| Cost to acquire new delivery customer | $12–$18 | Industry average |\n| Review-driven repeat order rate uplift | +22% | Yotpo restaurant case studies |\n| TAM (US cashback marketing tools, restaurants) | $820M | Frost & Sullivan 2023 |\n\n## 3. Competitive Landscape\n\n| Competitor | Focus | Users | Strengths | Weaknesses |\n|---|---|---|---|---|\n| Podium | SMS review requests | 100K+ SMBs | Brand recognition, multi-industry | No cashback, expensive |\n| Thanx | Loyalty + CRM for restaurants | 500+ chains | Deep POS integration | Enterprise only, $1,500+/mo |\n| Ovation | Guest recovery + review nudge | 5,000+ | Real-time alerts | No automated payout |\n| Incentivio | Digital loyalty suite | 3,000+ restaurants | App-based loyalty | Requires custom app download |\n| Manual DIY | Venmo + notes | Majority of SMBs | $0 cost | Unsustainable at scale, fraud risk |\n\n## 4. Target User Personas\n\n**Persona 1 — Rosa, 52, Cuban Restaurant Owner, Miami FL**\nRosa''s restaurant gets 65 Uber Eats orders/day. Her 4.1 star rating costs her ~15% of potential orders versus nearby 4.6-star competitors. She has tried asking delivery drivers to include notes asking for reviews, but it doesn''t work. She wants something that reaches diners directly after the order without her doing anything.\n\n**Persona 2 — Devon, 29, Food Truck Owner turned Ghost Kitchen, Austin TX**\nDevon pivoted to delivery-only during COVID and never went back. He has 0 foot traffic, so delivery ratings are everything. He''s scrappy and hates subscriptions — a percentage-of-payout model means he only pays when he gets results.\n\n**Persona 3 — Linda, 46, Dim Sum Restaurant Co-owner, San Francisco CA**\nLinda manages operations while her husband cooks. She doesn''t have time to learn complex dashboards. She wants a simple setup: paste in her restaurant''s delivery links, print a QR code, tape it to the bag, and let it run. Monthly check-in is fine.\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|---|---|---|\n| P0 | QR-code receipt insert generator | Printable PDF with unique per-restaurant cashback offer code |\n| P0 | Diner review submission portal | Mobile web page where diner submits screenshot proof of review |\n| P0 | Manual + automated review verification | AI screenshot parser + human spot-check for fraud prevention |\n| P0 | Payout via Venmo/PayPal to diner | Cashback delivered within 2 hours of verified review |\n| P1 | Restaurant dashboard | Total reviews generated, payout spend, star rating trend |\n| P1 | Offer customization | Set cashback amount ($1–$5), max reviews/day, minimum order value |\n| P1 | Multi-platform support | Accept screenshots from DoorDash, Uber Eats, Grubhub, Yelp |\n| P2 | Diner loyalty profile | Returning reviewers get priority payout + bonus offers |\n| P2 | Weekly email digest for owners | Review count, spend, rating change, top reviewer highlights |\n| P2 | Referral program for restaurants | $50 credit for referring another restaurant |\n\n## 6. Technical Architecture\n\n**Tech Stack:**\n- Backend: Python 3.12 + FastAPI\n- Database: PostgreSQL 14 + S3 (screenshot storage)\n- AI verification: OpenAI Vision API (GPT-4o) for screenshot parsing\n- Payments: PayPal Payouts API + Venmo for Business\n- Frontend: Next.js 14 + Tailwind CSS (restaurant dashboard + diner portal)\n- Infrastructure: Railway.app (MVP) → AWS ECS (scale)\n- Auth: Magic link email (Postmark)\n\n**Architecture Description:**\nDiners land on a mobile-optimized portal via QR code, upload a review screenshot, and receive a payout confirmation. Screenshots are stored in S3 and passed to GPT-4o Vision for star rating extraction and platform verification. Verified submissions trigger the PayPal payout job. Restaurant owners access a read-only dashboard showing aggregated review and spend data. The system is intentionally simple: no POS integration needed, no delivery platform API access required.\n\n## 7. Business Model\n\n| Revenue Source | Model | Expected % of Revenue |\n|---|---|---|\n| Transaction fee on cashback payouts | 8% of each cashback amount distributed | 65% |\n| Premium dashboard subscription | $29/mo for advanced analytics + A/B testing | 20% |\n| Verified badge program | $49/mo for "Verified StarCash Restaurant" badge in diner portal | 10% |\n| White-label for food delivery aggregators | Custom pricing per partner | 5% |\n\n## 8. MVP Roadmap\n\n| Month | Milestone |\n|---|---|\n| M1 | QR code generator + diner submission portal + manual verification flow |\n| M2 | GPT-4o screenshot verification + PayPal payout automation + basic restaurant dashboard |\n| M3 | Venmo payout support + multi-platform screenshot support + fraud scoring |\n| M4 | Premium analytics tier + referral program + onboard 50 pilot restaurants |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M6 Target |\n|---|---|---|\n| Active restaurant accounts | 30 | 120 |\n| Monthly cashback distributed | $4,500 | $22,000 |\n| Platform take rate (gross revenue) | $360 | $1,760 |\n| Screenshot fraud rate | <5% | <2% |\n| Diner-to-review conversion (QR scan → review) | 18% | 25% |\n| Avg. star rating lift per restaurant (3 mo) | +0.15 stars | +0.28 stars |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|---|---|---|---|\n| Delivery platforms flag cashback-for-review as manipulation | High | Critical | Legal counsel; offer as "loyalty thank-you" with no rating requirement |\n| Screenshot forgery by diners | Medium | High | GPT-4o metadata check + order ID cross-reference + payout hold period |\n| Low QR scan rate (diners ignore bag inserts) | High | Medium | Test SMS delivery confirmation with review link as alternative channel |\n| PayPal account holds on new business payouts | Medium | High | Pre-fund escrow account; maintain Venmo fallback; ACH backup |\n| Restaurant owner payment disputes | Low | Medium | Clear ToS; payout only after verification; dispute resolution SLA |\n', '[{"step":"business_model","decision":"Transaction fee (no subscription)","reason":"Removes adoption friction for cash-conscious SMB owners; aligns incentives — we earn only when they earn reviews"},{"step":"verification_approach","decision":"AI screenshot parsing (GPT-4o Vision)","reason":"Avoids need for delivery platform API agreements; works with any platform; deployable in M1"},{"step":"diner_acquisition","decision":"QR code on bag insert, not SMS","reason":"SMS requires phone number collection which adds compliance burden; QR code is zero-friction and owner-controlled"},{"step":"payment_provider","decision":"PayPal primary, Venmo secondary","reason":"PayPal Payouts has highest coverage across diner demographics; Venmo skews younger, adding M2"},{"step":"infrastructure","decision":"Railway.app for MVP","reason":"Zero DevOps overhead for solo founder; migrate to AWS when MRR exceeds $5k"},{"step":"fraud_mitigation","decision":"GPT-4o screenshot parsing + 2hr payout hold","reason":"Hold period allows spot-check without blocking most legitimate diners"}]', 'submitted', 38, NOW() - INTERVAL '27 days', NOW() - INTERVAL '28 days', NOW() - INTERVAL '27 days'),

(1, 8, E'# RateReturn: POS-Integrated Review Cashback for Restaurant Chains and Franchises\n\n## 1. Executive Summary\n\nRateReturn is a white-label review cashback platform designed for multi-unit restaurant operators and franchise groups who need centralized campaign management across locations. By integrating directly with major POS systems (Square, Toast, Clover) rather than delivery platform APIs, RateReturn captures both dine-in and delivery orders, giving operators a unified review acquisition channel. The platform targets operators running 3–15 locations with 50–200 daily delivery orders per unit, filling the gap between single-restaurant tools and expensive enterprise solutions.\n\n## 2. Market Analysis\n\n| Metric | Value | Source / Notes |\n|---|---|---|\n| US multi-unit independent operators (3–15 loc) | ~42,000 groups | NRA 2024 |\n| Average monthly marketing spend per location | $1,200–$2,800 | Constant Contact SMB survey |\n| Online review influence on restaurant selection | 88% of diners consult reviews | BrightLocal 2024 |\n| Avg. revenue lift from 4.0 → 4.5 star rating | +18% | Cornell Hospitality Research |\n| Delivery platform review response rate (unprompted) | 6–9% | Yotpo industry data |\n| Franchise group marketing compliance pain point | Top 3 operational issue | Franchise Business Review 2023 |\n| US POS market penetration (Square + Toast + Clover) | ~58% of independent restaurants | Second Measure 2023 |\n| SAM (multi-unit operators needing review automation) | ~$95M | Internal sizing |\n\n## 3. Competitive Landscape\n\n| Competitor | Focus | Users | Strengths | Weaknesses |\n|---|---|---|---|---|\n| Podium | Review request via SMS | 100K+ | Strong SMB base, easy onboarding | No POS sync, no cashback |\n| Yext | Listings + review management | 500K+ | Enterprise-grade, deep integrations | $600+/mo, no cashback payout |\n| Reputation.com | Enterprise reputation suite | 2,000+ enterprises | Multi-location analytics | Minimum $2K/mo, not SMB-accessible |\n| Ovation | Real-time guest feedback | 5,000+ restaurants | Fast recovery alerts | No proactive cashback, single-location focus |\n| Loyal (formerly Punchh) | Loyalty + CRM | 200+ chains | Deep loyalty data | Franchise-only, $3K+/mo |\n\n## 4. Target User Personas\n\n**Persona 1 — Greg, 47, Franchisee of 6 Sandwich Shops, Charlotte NC**\nGreg owns six Subway-adjacent franchise locations. His franchisor mandates he maintain a 4.3+ aggregate rating or risk territory review. He currently pays a virtual assistant $800/mo to manually request reviews. He needs a system that runs campaigns identically across all six locations with one login.\n\n**Persona 2 — Tiffany, 39, Regional Ops Director, 12-location Fast Casual Chain, Dallas TX**\nTiffany oversees marketing compliance for a regional burger chain. She needs campaign consistency: same cashback amount, same review platform targeting, same payout timing across all locations. Her nightmare is one location running a different campaign that creates inconsistent customer expectations.\n\n**Persona 3 — Carlos, 55, Multi-concept Restaurant Group Owner, Chicago IL**\nCarlos owns three different restaurant concepts (Italian, Mexican, Seafood) each with 2–3 locations. He wants a single dashboard that separates campaigns by brand while sharing one billing account. Tech-skeptical but delegates to his 28-year-old operations manager.\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|---|---|---|\n| P0 | POS webhook integration (Square, Toast, Clover) | Capture completed orders in real time across all platforms |\n| P0 | Centralized campaign manager | Create, clone, pause campaigns across all locations from one dashboard |\n| P0 | Review verification (DoorDash, Uber Eats, Google, Yelp) | Multi-platform review detection tied to order records |\n| P0 | Automated ACH/PayPal payout to customer | Sub-2hr cashback delivery after review verification |\n| P1 | Location-level performance reporting | Per-location review count, spend, star trend, payout efficiency |\n| P1 | Franchisor compliance dashboard | Read-only view for brand HQ to monitor all franchisee campaigns |\n| P1 | Customer review history & dedup | Prevent repeat cashbacks from same customer within 30-day window |\n| P2 | Slack/email alerts for rating drops | Notify ops team if location drops below threshold |\n| P2 | Campaign budget controls | Daily/monthly cashback spend caps with automatic pause |\n| P2 | API access for custom POS integrations | REST API for operators with proprietary POS systems |\n\n## 6. Technical Architecture\n\n**Tech Stack:**\n- Backend: Go 1.22 + Chi router (high-throughput webhook processing)\n- Database: PostgreSQL 16 + TimescaleDB extension (time-series review analytics)\n- Queue: RabbitMQ (order events → review check jobs)\n- POS Integrations: Square Webhooks API, Toast Webhooks, Clover REST API\n- Payment: PayPal Payouts API + ACH via Stripe Treasury\n- Review Polling: Custom scrapers + official APIs (Google My Business, Yelp Fusion)\n- Frontend: Next.js 15 + Tailwind CSS + Recharts\n- Infrastructure: AWS ECS + RDS PostgreSQL + ElastiCache Redis\n- Auth: Auth0 with multi-tenant org support\n\n**Architecture Description:**\nPOS events are ingested via webhooks into a RabbitMQ queue, where Go consumers upsert order records and schedule review-check jobs with exponential backoff (check at +15min, +1hr, +6hr, +24hr post-order). Review detection runs across Google, Yelp, DoorDash, and Uber Eats APIs. Verified reviews trigger an idempotent payout job. Multi-tenant data isolation is enforced at the PostgreSQL row-security-policy level, allowing the same DB cluster to serve all operators safely. The franchisor compliance view is a read-only materialized view refreshed every hour.\n\n## 7. Business Model\n\n| Revenue Source | Model | Expected % of Revenue |\n|---|---|---|\n| Per-location subscription | $59/location/mo (3–5 loc), $49/loc (6–15 loc) | 60% |\n| Franchisor compliance portal | $199/mo flat (unlimited franchisee read-only access) | 15% |\n| API access tier | $299/mo for custom POS integrations + higher rate limits | 12% |\n| Setup & training | $299 one-time per account | 8% |\n| Revenue share on payout volume | 0.2% on all cashback disbursed | 5% |\n\n## 8. MVP Roadmap\n\n| Month | Milestone |\n|---|---|\n| M1 | Square POS integration + PostgreSQL multi-tenant schema + basic campaign dashboard |\n| M2 | Toast + Clover integrations + Google/Yelp review polling + PayPal payout automation |\n| M3 | DoorDash + Uber Eats review polling + location-level analytics + billing (Stripe) |\n| M4 | Franchisor compliance portal + Slack alerts + ACH via Stripe Treasury + public launch |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M6 Target |\n|---|---|---|\n| Paying operator accounts | 15 | 60 |\n| Total locations managed | 55 | 240 |\n| MRR | $3,300 | $14,000 |\n| Review detection accuracy | >92% | >96% |\n| Payout error rate | <0.5% | <0.2% |\n| Avg. star rating lift per location (90 days) | +0.2 stars | +0.35 stars |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|---|---|---|---|\n| POS API breaking changes | Medium | High | Version-pin integrations; monitor changelogs; 30-day buffer clause in ToS |\n| Review platform TOS prohibiting incentivized reviews | High | Critical | Legal review; frame as post-purchase loyalty reward; no star-rating requirement |\n| Multi-tenant data leak | Low | Critical | Row-level security + integration tests + quarterly pen test |\n| Low conversion on ACH (customers prefer Venmo) | Medium | Medium | Add Venmo for Business as fallback in M2 |\n| Franchise HQ resistance to third-party tools | Medium | High | Build compliance dashboard first; lead with HQ pitch, not franchisee pitch |\n', '[{"step":"target_segment","decision":"Multi-unit operators (3–15 locations)","reason":"Higher ACV per account vs single-unit; franchise compliance angle creates stickier retention"},{"step":"integration_strategy","decision":"POS-first (Square/Toast/Clover) not delivery platform APIs","reason":"POS APIs are more stable and accessible; covers both dine-in and delivery from one integration"},{"step":"tech_stack","decision":"Go + RabbitMQ for webhook processing","reason":"Go handles high concurrency at low memory cost; RabbitMQ gives durable job queue for retry logic"},{"step":"pricing_model","decision":"Per-location subscription","reason":"Predictable revenue; scales naturally with operator growth; easy for multi-unit operators to justify per-unit"},{"step":"database","decision":"PostgreSQL + TimescaleDB","reason":"Time-series extension handles review trend queries efficiently without separate analytics DB"},{"step":"go_to_market","decision":"Target franchise groups first via franchisor HQ","reason":"One HQ deal unlocks dozens of franchisee accounts simultaneously; highest leverage GTM for multi-tenant product"}]', 'submitted', 53, NOW() - INTERVAL '25 days', NOW() - INTERVAL '26 days', NOW() - INTERVAL '25 days');

