INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(5, 13, E'# QuoteDraft: AI-Powered Renovation Quote Generator for Small Contractors\n\n## 1. Executive Summary\n\nQuoteDraft is a web-based quoting tool that lets small renovation contractors generate detailed, itemized quotes in under 20 minutes by combining a room-by-room floor plan input with a material selection catalog. Instead of building quotes from scratch in Excel or Word, contractors walk through a guided wizard — rooms, dimensions, finish categories — and QuoteDraft auto-calculates labor hours, material quantities, and markups, producing a professional PDF quote ready to send to the client. The platform targets small renovation companies handling 30–80 projects per year, where quote preparation currently consumes 3–5 hours per project.\n\n## 2. Market Analysis\n\n| Metric | Value | Source / Notes |\n|---|---|---|\n| Small renovation contractors (US, <10 employees) | ~380,000 | US Census Bureau 2023 |\n| Avg. projects per year (target: 30–80) | 50 | Internal survey |\n| Avg. time spent on quote preparation | 3.5 hrs/project | NAHB contractor survey 2024 |\n| Avg. quote-to-close rate (small contractors) | 34% | Houzz Pro contractor report 2024 |\n| Quote-to-close rate improvement with professional PDF | +12 pts | Same source |\n| Material cost as % of renovation project | 40–55% | RSMeans 2024 data |\n| Avg. project value (target segment) | $18,000–$85,000 | NAHB remodeling market index |\n| US residential renovation market | $485B | Harvard Joint Center 2024 |\n\n## 3. Competitive Landscape\n\n| Competitor | Focus | Users | Strengths | Weaknesses |\n|---|---|---|---|---|\n| Houzz Pro | Project management + quotes | 3M+ professionals | Brand recognition, large audience | Expensive ($65–$375/mo), complex |\n| Buildertrend | Construction project management | 1M+ users | Comprehensive feature set | Enterprise-focused, $499+/mo |\n| Jobber | Field service + quoting | 200,000+ | Excellent quote UX | Not renovation-specific; no material catalog |\n| PlanSwift | Takeoff + estimating | 100,000+ | Accurate takeoff | Steep learning curve, desktop-only |\n| Excel template | Manual | ~60% small contractors | Free, familiar | Not client-facing, error-prone, slow |\n\n## 4. Target User Personas\n\n**Persona 1 — Paul, 47, General Contractor, Charlotte NC**\nPaul runs a 4-person renovation crew doing 45 projects per year (kitchens, bathrooms, additions). He currently spends Sunday evenings building quotes in Excel. His close rate is 31% — he suspects his quotes look unprofessional compared to bigger firms. He wants a tool that produces a branded, itemized PDF he can email directly from his phone after a walkthrough.\n\n**Persona 2 — Diana, 38, Interior Renovation Specialist, Denver CO**\nDiana focuses on high-end kitchen and bathroom remodels ($40K–$120K range). Her clients are design-conscious and expect material options (tile A vs tile B) with price comparisons in the quote. She wants a quoting tool that supports "option packages" — let the client choose between Standard, Premium, and Luxury finish tiers.\n\n**Persona 3 — Steve, 54, Handyman turned General Contractor, Tampa FL**\nSteve recently scaled from handyman to taking on full renovation projects. He has no estimating experience and frequently under-bids. He wants a system that has built-in labor rate benchmarks (from RSMeans or similar) so he stops losing money on jobs he mispriced.\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|---|---|---|\n| P0 | Project wizard (room + dimensions) | Step-by-step: project type, rooms, sq footage, scope selection |\n| P0 | Material catalog with unit pricing | Pre-loaded catalog of 500+ common renovation materials with regional pricing |\n| P0 | Auto-calculated itemized quote | Labor hours, material qty, markup, tax, total — auto-calculated |\n| P0 | PDF quote generation | Branded, professional PDF with contractor logo + client details |\n| P1 | Option packages (Good/Better/Best) | Client-facing comparison of multiple finish tiers in one quote |\n| P1 | Quote versioning | Save multiple quote versions per project; track which was accepted |\n| P1 | Client e-sign + acceptance | Client signs quote via DocuSign-like embedded flow |\n| P2 | Material price sync (regional) | Sync material prices with regional supplier catalogs quarterly |\n| P2 | Project-to-invoice conversion | Convert accepted quote to invoice with one click |\n| P2 | Change order management | Add scope changes to live project; auto-update total |\n\n## 6. Technical Architecture\n\n**Tech Stack:**\n- Backend: Node.js 20 + Express\n- Database: PostgreSQL 15 + Redis\n- PDF generation: Puppeteer (HTML template → PDF)\n- E-sign: HelloSign (Dropbox Sign) API\n- Material catalog: PostgreSQL materialized view with regional price overrides\n- Frontend: React 18 + Vite + shadcn/ui\n- File storage: AWS S3 (generated PDFs + signed documents)\n- Hosting: AWS ECS Fargate\n- Auth: Auth0\n\n**Architecture Description:**\nThe quote calculation engine is a pure TypeScript service that takes a project scope object and applies: (1) material quantities based on room dimensions and scope type, (2) labor hours from a configurable labor rate table, (3) contractor markup percentage, (4) regional tax rate. This engine is stateless and unit-tested. Puppeteer renders the quote HTML template server-side and saves the PDF to S3. The HelloSign API creates a signature request linking to the stored PDF; on signature completion, a webhook marks the quote as accepted in PostgreSQL. The material catalog is maintained as a JSON seed updated quarterly from RSMeans pricing data.\n\n## 7. Business Model\n\n| Revenue Source | Model | Expected % of Revenue |\n|---|---|---|\n| Monthly subscription | $79/mo (up to 80 projects/yr), $129/mo (unlimited) | 68% |\n| Per-quote PDF export | $2/quote for non-subscribers (freemium hook) | 12% |\n| E-sign add-on | $19/mo for unlimited client e-signatures | 11% |\n| Material catalog premium tier | $15/mo for real-time regional price sync | 6% |\n| Setup & onboarding | One-time $149 (customized labor rates + branding) | 3% |\n\n## 8. MVP Roadmap\n\n| Month | Milestone |\n|---|---|\n| M1 | Project wizard + quote calculation engine + basic PDF generation (Puppeteer) |\n| M2 | Material catalog (500 items) + contractor branding + quote versioning |\n| M3 | Client e-sign (HelloSign) + option packages (Good/Better/Best) + dashboard |\n| M4 | Stripe billing + regional price sync + invoice conversion + 30 pilot contractors |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M6 Target |\n|---|---|---|\n| Paying contractors | 30 | 120 |\n| MRR | $2,800 | $11,500 |\n| Avg. quote generation time | <25 min | <18 min |\n| Quote-to-close rate (users vs non-users) | +8 pts | +14 pts |\n| PDF quote send rate (% of quotes sent to client) | 78% | 85% |\n| E-sign acceptance rate | 45% | 58% |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|---|---|---|---|\n| Material pricing inaccuracy causing contractor losses | High | Critical | Clearly label prices as "estimates"; allow contractor to override any line item |\n| Contractors don''t trust auto-calculated labor | High | High | Show calculation logic transparently; let contractor set their own labor rates |\n| RSMeans pricing data license cost | Medium | Medium | Use public contractor survey data initially; license RSMeans at $5K MRR |\n| HelloSign API pricing increases | Low | Medium | Abstract e-sign behind interface; swap to Adobe Sign or docuseal.co |\n| Slow contractor adoption (tech-averse segment) | High | High | YouTube walkthrough videos + phone onboarding for first 50 customers |\n', '[{"step":"core_value_prop","decision":"Speed + professionalism (not accuracy guarantee)","reason":"Contractors don''t trust software to be 100% accurate; framing as ''faster, more professional quotes'' removes accuracy liability"},{"step":"calculation_engine","decision":"Stateless TypeScript service","reason":"Fully unit-testable; no database dependency; can be validated independently before UI is built"},{"step":"pdf_generation","decision":"Puppeteer (HTML→PDF)","reason":"HTML/CSS templates are easy to brand and maintain; Puppeteer produces pixel-perfect results vs server-side PDF libraries"},{"step":"e_sign","decision":"HelloSign API (not DocuSign)","reason":"HelloSign API is $20/mo vs DocuSign $300+/mo; sufficient for quote acceptance; not legally complex"},{"step":"material_catalog","decision":"500 items hand-curated for M1","reason":"Comprehensive catalog is a long-term moat; start with 500 most common items based on NAHB cost-to-build data"},{"step":"pricing","decision":"$79/mo entry","reason":"Below Jobber at $49 tier but with renovation-specific features; above perceived ''cheap'' threshold; covers COGS at 20 accounts"}]', 'submitted', 51, NOW() - INTERVAL '27 days', NOW() - INTERVAL '28 days', NOW() - INTERVAL '27 days'),

(5, 17, E'# SketchQuote: Floor Plan Upload to Instant Renovation Estimate\n\n## 1. Executive Summary\n\nSketchQuote allows contractors to photograph or upload a hand-drawn or digital floor plan, uses computer vision to extract room dimensions, and generates a draft itemized quote within 90 seconds. The AI-assisted extraction eliminates the manual dimension-entry step that slows down every existing quoting tool. Combined with a client-facing interactive quote portal where homeowners can swap materials and see price changes in real time, SketchQuote shortens the quote-to-approval cycle from 3–5 days to same-day. It targets small renovation companies handling 30–80 projects per year.\n\n## 2. Market Analysis\n\n| Metric | Value | Source / Notes |\n|---|---|---|\n| US residential renovation spend | $485B | Harvard JCHS 2024 |\n| Projects using digital floor plan tools | 28% of small contractors | NAHB tech adoption survey |\n| Avg. back-and-forth emails per quote revision | 4.2 exchanges | Houzz Pro report 2024 |\n| Time lost to client quote revision requests | 1.8 hrs/project avg | Same source |\n| Homeowner expectation: receive quote within | 24 hours | HomeAdvisor consumer survey 2024 |\n| % of contractors who lose jobs due to slow quotes | 29% | NAHB 2024 |\n| AI-assisted document extraction accuracy (GPT-4o) | 91–94% for structured drawings | OpenAI published benchmarks |\n| SOM (Year 1 US, AI quoting for small remodelers) | ~$4.2M | Bottom-up estimate |\n\n## 3. Competitive Landscape\n\n| Competitor | Focus | Users | Strengths | Weaknesses |\n|---|---|---|---|---|\n| PlanSwift | Manual digital takeoff | 100,000+ | Accurate, industry standard | No AI extraction; desktop-only; 3-day learning curve |\n| Houzz Pro | Quoting + project mgmt | 3M+ professionals | Large network | No floor plan extraction; $65+/mo |\n| Stack (ConstructConnect) | Commercial estimating | 50,000+ | Powerful AI takeoff | Commercial-focused; $2,400+/yr |\n| Roofr | Roofing-specific estimating | 15,000+ | AI satellite roof measurement | Roofing only |\n| Manual (photos + Excel) | DIY | ~60% small contractors | Free | Slow, error-prone, unprofessional |\n\n## 4. Target User Personas\n\n**Persona 1 — Ryan, 33, Kitchen Remodel Specialist, Minneapolis MN**\nRyan does 55 kitchen remodels per year. Every client gives him a different kind of "floor plan" — a napkin sketch, an architect''s PDF, a photo of the existing room. He wants to stop typing in dimensions manually and just upload whatever the client sends him. If AI can read the dimensions, he saves 45 minutes per quote.\n\n**Persona 2 — Elena, 41, Renovation Project Manager, San Jose CA**\nElena manages quotes for a 6-person crew. She sends quotes to affluent tech professionals who want an interactive experience — they want to swap granite countertop options and see the price update live before signing. Static PDF quotes feel outdated to her clients. She needs a client portal, not just a PDF.\n\n**Persona 3 — Marcus, 50, Whole-Home Renovation Contractor, Nashville TN**\nMarcus takes on large whole-home renovations (15+ rooms). His quotes are complex — 40-line-item documents that take him 8 hours to build. He wants AI to draft the structure from a floor plan so he can review and adjust, not build from zero. Accuracy doesn''t need to be perfect — he''ll review everything — but a 70% draft saves him hours.\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|---|---|---|\n| P0 | Floor plan upload + AI dimension extraction | Upload photo/PDF; GPT-4o Vision extracts room names, dimensions, square footage |\n| P0 | Scope selection per room | Contractor selects renovation scope: full remodel, flooring only, paint only, etc. |\n| P0 | Auto-generated itemized estimate | Material quantities + labor hours calculated from extracted dimensions + scope |\n| P0 | PDF quote output | Branded PDF quote generated from estimate data |\n| P1 | Interactive client portal | Client views quote online; swaps material options; sees live price update |\n| P1 | Material option library | 3 finish tiers (Standard / Premium / Luxury) per material category |\n| P1 | Quote approval + e-sign | Client signs online; contractor receives notification |\n| P2 | Dimension correction UI | Contractor corrects AI extraction errors before generating quote |\n| P2 | Project template library | Save common project types as reusable templates |\n| P2 | Supplier price import | Upload supplier price list CSV; override catalog prices |\n\n## 6. Technical Architecture\n\n**Tech Stack:**\n- Backend: Python 3.12 + FastAPI\n- AI extraction: OpenAI GPT-4o Vision API (floor plan parsing)\n- Database: PostgreSQL 16 + S3 (floor plan images + generated PDFs)\n- Quote calculation: Python service (room dimensions × scope → materials + labor)\n- PDF generation: WeasyPrint (HTML/CSS → PDF)\n- Client portal: Next.js 15 + Tailwind CSS (interactive material swapper)\n- Real-time price updates: Server-Sent Events (SSE) on material selection\n- E-sign: Docuseal (open-source, self-hosted; zero per-sign cost)\n- Hosting: Railway.app\n- Auth: Clerk (contractor auth) + signed URL (client portal)\n\n**Architecture Description:**\nWhen a contractor uploads a floor plan, the image is stored in S3 and a FastAPI background task calls GPT-4o Vision with a structured prompt requesting JSON output (room_name, width_ft, length_ft, area_sqft). The extracted data is stored as a draft project with a correction UI allowing the contractor to fix OCR errors before proceeding. The quote calculation service is a pure Python function (no I/O) that maps rooms × scope_type to material quantities using a lookup table, then applies regional labor rates. The client portal is a Next.js app served from a signed URL; material swap events call a calculation endpoint that returns updated line items via SSE. Docuseal is deployed as a Docker container on the same Railway project.\n\n## 7. Business Model\n\n| Revenue Source | Model | Expected % of Revenue |\n|---|---|---|\n| Monthly subscription | $89/mo (up to 80 projects/yr) | 62% |\n| AI extraction credits | 10 free extractions/mo included; $0.50/extraction overage | 18% |\n| Client portal add-on | $24/mo for unlimited interactive client portals | 12% |\n| Annual plan | $890/yr ($178 savings) | (reduces churn) |\n| Template marketplace | Contractors sell project templates; 20% revenue share | 5% |\n| API access | $199/mo for builder management platforms | 3% |\n\n## 8. MVP Roadmap\n\n| Month | Milestone |\n|---|---|\n| M1 | GPT-4o floor plan extraction + dimension correction UI + basic quote calculation |\n| M2 | PDF generation (WeasyPrint) + material catalog + contractor branding |\n| M3 | Interactive client portal (Next.js + SSE) + material options + e-sign (Docuseal) |\n| M4 | Stripe billing + AI credit system + project templates + 25 pilot contractors |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M6 Target |\n|---|---|---|\n| Paying contractors | 25 | 95 |\n| MRR | $2,600 | $10,800 |\n| Floor plan extraction accuracy (no correction needed) | 72% | 82% |\n| Avg. quote generation time | <20 min | <12 min |\n| Client portal engagement (opens interactive quote) | 60% | 70% |\n| Quote acceptance rate (signed vs sent) | 48% | 60% |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|---|---|---|---|\n| GPT-4o extraction accuracy below 70% for hand-drawn plans | High | High | Add manual dimension override UI as primary fallback; set expectation as "AI draft" |\n| OpenAI API cost per extraction ($0.08–$0.15/image) | Medium | Medium | Include 10 free/mo; charge $0.50 overage; use GPT-4o mini for simple plans |\n| Docuseal self-hosted maintenance overhead | Low | Low | Docuseal is low-maintenance; fallback to HelloSign API if needed |\n| Contractors don''t trust AI-extracted dimensions | High | Medium | Show extraction confidence score; highlight low-confidence fields for manual review |\n| Client portal seen as unnecessary complexity | Medium | Medium | Make portal optional; default to PDF-only; upsell portal as premium |\n', '[{"step":"core_differentiator","decision":"AI floor plan extraction (not just wizard)","reason":"Eliminates biggest friction point in quoting (manual dimension entry); defensible technical moat vs form-based competitors"},{"step":"ai_model","decision":"GPT-4o Vision","reason":"Best-in-class vision accuracy for architectural drawings; API available today; cost manageable at $0.08–0.15/image"},{"step":"client_portal","decision":"Interactive material swapper with SSE","reason":"Real-time price feedback matches how affluent homeowners shop online; reduces revision cycles from 4 to 1"},{"step":"e_sign","decision":"Docuseal self-hosted","reason":"Zero per-sign cost at any volume; open-source; avoids per-document fees that erode margin at scale"},{"step":"extraction_ux","decision":"Correction UI before calculation","reason":"AI accuracy is 72–82%; contractor must verify; making correction easy removes trust barrier without requiring 100% accuracy"},{"step":"pricing","decision":"AI extraction credits as separate meter","reason":"Aligns revenue with usage; heavy users (80 projects/yr) pay more; light users pay less; prevents underpricing the AI compute cost"}]', 'submitted', 43, NOW() - INTERVAL '31 days', NOW() - INTERVAL '32 days', NOW() - INTERVAL '31 days'),

(5, 24, E'# BidBlueprint: CRM-Integrated Quoting for Renovation Companies with Sales Pipelines\n\n## 1. Executive Summary\n\nBidBlueprint combines renovation quote generation with a lightweight sales pipeline CRM, giving small renovation companies a single tool for the entire pre-construction sales process: lead capture, site visit notes, quote generation, follow-up automation, and win/loss tracking. While competitors focus on quote creation in isolation, BidBlueprint treats the quote as one step in a sales workflow — ensuring no lead falls through the cracks and every quote is followed up. It targets renovation companies doing 30–80 projects per year with 1–3 salespeople handling inbound leads.\n\n## 2. Market Analysis\n\n| Metric | Value | Source / Notes |\n|---|---|---|\n| US small renovation companies (1–10 employees) | ~380,000 | US Census Bureau 2023 |\n| Avg. lead-to-quote conversion rate (small contractors) | 58% | Houzz Pro 2024 |\n| Avg. quote-to-close rate | 34% | Same source |\n| % of leads lost due to slow follow-up | 27% | HomeAdvisor 2024 |\n| Avg. time to first follow-up after quote send | 6.2 days | HubSpot construction benchmark |\n| Optimal follow-up window for quote conversion | 24–48 hours | Velocify sales research |\n| % of small contractors using a CRM | 12% | Buildertrend market survey 2023 |\n| Potential revenue recovery from systematic follow-up | +$31,000/yr per company | Calculated at 34% → 45% close rate |\n\n## 3. Competitive Landscape\n\n| Competitor | Focus | Users | Strengths | Weaknesses |\n|---|---|---|---|---|\n| Jobber | Field service CRM + quoting | 200,000+ | Best-in-class quoting UX | No renovation-specific material catalog; weak pipeline |\n| Houzz Pro | Project management + leads | 3M+ | Lead generation built-in | $375+/mo for CRM features; no pipeline tracking |\n| HubSpot Free | Generic CRM | Millions | Powerful free tier | Not renovation-specific; no quoting |\n| Buildertrend | Construction project mgmt | 1M+ | Full lifecycle | $499+/mo; overkill for 30–80 project companies |\n| Pipedrive + Jobber combo | CRM + quoting (two tools) | Various | Each tool is best-in-class | Two subscriptions, no data sync |\n\n## 4. Target User Personas\n\n**Persona 1 — Frank, 51, Owner/Salesperson, Kitchen & Bath Remodeler, Cincinnati OH**\nFrank generates leads from Angi (formerly Angie''s List) and word of mouth. He does 40 projects per year and estimates he loses 8–10 deals per year because he forgets to follow up after sending a quote. He wants a tool that reminds him to call the client 48 hours after the quote is sent, and shows him which quotes are still open.\n\n**Persona 2 — Christine, 44, Sales Manager, 6-person Renovation Firm, Scottsdale AZ**\nChristine manages two estimators. She wants a shared pipeline view where she can see every open quote, which estimator owns it, and how long it''s been since the last contact. Her current process: Slack messages and a shared Google Sheet. She needs a real CRM that doesn''t require a $300/mo HubSpot subscription.\n\n**Persona 3 — Darnell, 36, General Contractor Building a Team, Atlanta GA**\nDarnell is scaling from solo contractor to a 4-person company. He has no sales process. He needs a system that tells him what to do: log the lead, visit the site, send the quote, follow up in 2 days, follow up again in a week. A prescriptive pipeline with built-in tasks is more valuable than a flexible CRM he has to configure himself.\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|---|---|---|\n| P0 | Lead pipeline (Kanban board) | Stages: New Lead → Site Visit → Quote Sent → Follow-Up → Won/Lost |\n| P0 | Quote generator (room + material wizard) | Guided scope entry; auto-calculated itemized quote |\n| P0 | PDF quote with contractor branding | Professionally formatted, email-ready PDF |\n| P0 | Follow-up task automation | Auto-create follow-up task 48hrs after quote send; escalate if no response in 7 days |\n| P1 | Win/loss tracking + reason logging | Mark quote as won/lost; log reason; feed into analytics |\n| P1 | Email integration (Gmail/Outlook) | Log emails in lead timeline; send quote directly from BidBlueprint |\n| P1 | Team assignment (1–5 estimators) | Assign leads + quotes to team members; shared pipeline view |\n| P2 | Lead source tracking | Tag leads by source (Angi, Houzz, referral, Google); track close rate by source |\n| P2 | Quote-to-project handoff | Won quote converts to project record with scope, timeline, materials list |\n| P2 | Revenue forecasting | Pipeline value × avg. close rate = projected monthly revenue |\n\n## 6. Technical Architecture\n\n**Tech Stack:**\n- Backend: Go 1.22 + Echo v4\n- Database: PostgreSQL 16\n- Email integration: Gmail API + Microsoft Graph API (OAuth)\n- PDF generation: Go + wkhtmltopdf (HTML template → PDF)\n- Frontend: React 18 + Vite + Tailwind CSS + React DnD (Kanban drag-and-drop)\n- Background jobs: Go goroutines + pg_cron (follow-up task scheduling)\n- Notifications: Twilio SMS + Resend email\n- Hosting: Fly.io (Go backend) + Vercel (React frontend)\n- Auth: Auth0 with team/org support\n\n**Architecture Description:**\nThe pipeline is a PostgreSQL state machine: each lead has a stage enum (new/site_visit/quote_sent/followup/won/lost) with a stage_changed_at timestamp. When a quote is marked as sent, a pg_cron job inserts a follow_up_task record for T+48hr. If the task is not completed, another job at T+7d creates an escalation notification. The Go backend serves a REST API consumed by the React frontend. Kanban drag-and-drop uses React DnD with optimistic updates backed by an idempotent PATCH endpoint. Gmail/Outlook integration uses OAuth tokens stored encrypted in PostgreSQL; email send events are logged to the lead timeline. PDF generation uses wkhtmltopdf running as a Go exec subprocess (containerized in the Fly.io app).\n\n## 7. Business Model\n\n| Revenue Source | Model | Expected % of Revenue |\n|---|---|---|\n| Monthly subscription | $69/mo solo, $119/mo team (up to 5 users) | 74% |\n| Email integration add-on | $15/mo for Gmail + Outlook sync | 12% |\n| Revenue forecasting module | $19/mo add-on | 7% |\n| Setup & pipeline configuration | One-time $199 | 4% |\n| Lead source analytics report | $9/mo add-on | 3% |\n\n## 8. MVP Roadmap\n\n| Month | Milestone |\n|---|---|\n| M1 | Lead pipeline (Kanban) + PostgreSQL schema + basic quote generator + PDF output |\n| M2 | Follow-up task automation (pg_cron) + Twilio SMS alerts + win/loss tracking |\n| M3 | Team assignment + shared pipeline view + Gmail integration (OAuth) |\n| M4 | Auth0 multi-user + Stripe billing + revenue forecasting + 35 pilot companies |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M6 Target |\n|---|---|---|\n| Paying companies | 30 | 110 |\n| MRR | $2,700 | $10,400 |\n| Avg. quote-to-follow-up time (platform users) | <52 hrs | <48 hrs |\n| Quote-to-close rate lift vs baseline (34%) | +7 pts | +12 pts |\n| Pipeline leads created per company/mo | 8 | 11 |\n| Team plan adoption rate (% of accounts) | 25% | 38% |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|---|---|---|---|\n| Contractors don''t update pipeline (CRM adoption) | High | High | Auto-advance pipeline stages on key events (quote sent → "Quote Sent" stage auto-updates) |\n| Gmail OAuth review process (Google verification) | Medium | High | Start with Outlook integration; pursue Google OAuth verification in parallel |\n| wkhtmltopdf licensing / maintenance | Low | Low | wkhtmltopdf is MIT-licensed; fallback to Puppeteer if deprecated |\n| Competing with free HubSpot | Medium | Medium | HubSpot has no quoting; BidBlueprint''s renovation-specific material catalog is the moat |\n| Small companies don''t want a "CRM" (intimidating word) | High | Medium | Market as "quote + follow-up tool"; avoid the word "CRM" in onboarding |\n', '[{"step":"core_differentiator","decision":"CRM pipeline + quoting in one tool (not quoting alone)","reason":"27% of leads lost to slow follow-up is a bigger revenue problem than quote quality; combining both solves the full revenue leak"},{"step":"pipeline_design","decision":"Auto-advance stages on system events","reason":"Contractors don''t manually update CRMs; auto-advancing on quote-sent, email-opened events reduces friction and keeps data clean"},{"step":"follow_up_automation","decision":"pg_cron for task scheduling","reason":"Avoids external scheduler dependency; PostgreSQL-native; sufficient for task volume of 30–80 projects/month per company"},{"step":"tech_stack","decision":"Go + Echo (matching Claway backend pattern)","reason":"Go handles concurrent webhook processing efficiently; Echo v4 is familiar; reduces context switching for development team"},{"step":"email_integration","decision":"Gmail first, Outlook second","reason":"Gmail has higher penetration among small US contractors; Microsoft Graph OAuth is complex; defer to M3"},{"step":"gtm","decision":"Angi/HomeAdvisor contractor community partnerships","reason":"Angi has 200K+ US contractors; sponsored content in their contractor newsletter reaches target segment at low CAC"}]', 'submitted', 22, NOW() - INTERVAL '42 days', NOW() - INTERVAL '43 days', NOW() - INTERVAL '42 days');

COMMIT;
